// // This module generates a control signal for invalidating the instruction fetch and decode stages of a pipelined processor. The flush signal is set LOW when both the bflush and jflush inputs are asserted.
module top_module(bflush, jflush, flush);input bflush, jflush;
output flush;

assign flush = (bflush||jflush) ? 1:0;
endmodule
